import json
import os
from typing import List, Dict, Any, Optional
from datetime import datetime
from src.config.settings import settings
import google.generativeai as genai

class MemoryManager:
    """
    Structured memory manager for the agent.
    Persists interaction history to JSON and implements recursive summarization
    (Infinite Memory Engine).
    """

    def __init__(self, session_id: str = "default"):
        self.session_id = session_id
        self.memory_file = os.path.join(settings.LOGS_DIR, f"memory_{session_id}.json")
        self.summary_file = os.path.join(settings.LOGS_DIR, f"memory_{session_id}_summary.txt")
        self._ensure_log_dir()
        self.history: List[Dict[str, Any]] = self._load_memory()
        self.summary: str = self._load_summary()

        # Configure Gemini for summarization if API key is available
        if settings.google_api_key:
            genai.configure(api_key=settings.google_api_key)
            self.model = genai.GenerativeModel('gemini-1.5-flash')
        else:
            self.model = None

    def _ensure_log_dir(self):
        os.makedirs(settings.LOGS_DIR, exist_ok=True)

    def _load_memory(self) -> List[Dict[str, Any]]:
        if os.path.exists(self.memory_file):
            with open(self.memory_file, "r") as f:
                return json.load(f)
        return []

    def _load_summary(self) -> str:
        if os.path.exists(self.summary_file):
            with open(self.summary_file, "r") as f:
                return f.read()
        return ""

    def _save_memory(self):
        with open(self.memory_file, "w") as f:
            json.dump(self.history, f, indent=2)

    def _save_summary(self):
        with open(self.summary_file, "w") as f:
            f.write(self.summary)

    def add_entry(self, role: str, content: str, metadata: Optional[Dict[str, Any]] = None):
        entry = {
            "timestamp": datetime.now().isoformat(),
            "role": role,
            "content": content,
            "metadata": metadata or {}
        }
        self.history.append(entry)
        self._save_memory()

        # Trigger summarization if history gets too long (e.g., > 20 entries)
        if len(self.history) > 20:
            self._summarize_history()

    def _summarize_history(self):
        """Compresses older history into the summary."""
        if not self.model:
            return

        # Take the first 10 entries to summarize
        chunk_to_summarize = self.history[:10]
        remaining_history = self.history[10:]

        text_chunk = json.dumps(chunk_to_summarize, indent=2)
        prompt = f"""
        You are the Memory Manager for an autonomous agent.
        Update the current summary with the new events provided.

        Current Summary:
        {self.summary}

        New Events:
        {text_chunk}

        Output the new, consolidated summary. Keep it concise but retain key decisions and facts.
        """

        try:
            response = self.model.generate_content(prompt)
            if response.text:
                self.summary = response.text
                self.history = remaining_history
                self._save_summary()
                self._save_memory()
                print("🧠 Memory summarized.")
        except Exception as e:
            print(f"⚠️ Memory summarization failed: {e}")

    def get_history(self) -> List[Dict[str, Any]]:
        return self.history

    def get_context(self) -> str:
        """Returns the full context: Summary + Recent History."""
        recent = json.dumps(self.history, indent=2)
        return f"PREVIOUS CONTEXT SUMMARY:\n{self.summary}\n\nRECENT HISTORY:\n{recent}"
